end

local function is_safe_path(p)
    if not p or p == "" then return false end
    if p:find("\0", 1, true) then return false end
    if p:sub(1, 1) == "/" or p:sub(1, 1) == "\\" then return false end
    if p:find(":", 1, true) then return false end
    if p:find("\\", 1, true) then return false end
    if p:find("//", 1, true) then return false end
    if p:find("/%.%./") or p:find("^%.%./") or p:find("/%.%.$") or p:find("^%.%.$") then return false end
    if p:find("/%./") or p:find("^%./") then return false end
    return true
end

